class RemoteCursor { final double x; final double y; final bool visible; final bool isClicking; const RemoteCursor({required this.x, required this.y, this.visible = true, this.isClicking = false}); RemoteCursor copyWith({double? x, double? y, bool? visible, bool? isClicking}) => RemoteCursor(x: x ?? this.x, y: y ?? this.y, visible: visible ?? this.visible, isClicking: isClicking ?? this.isClicking); }